-- Enhanced face module schemas: eyes (22), mouth (18), nose (17), skeletal (21)
-- Anatomical-grade parameters from ophthalmology, plastic surgery, rhinoplasty,
-- craniofacial surgery perspectives. All 4 tiers: basic → clinical.

-- eyes: 22 parameters
UPDATE luv_chassis_modules SET parameter_schema = '[{"key": "color", "label": "Iris Color", "type": "color", "tier": "basic", "default": "#4A90D9"}, {"key": "shape", "label": "Eye Shape", "type": "enum", "tier": "basic", "options": ["almond", "round", "hooded", "monolid", "upturned", "downturned", "deep-set", "prominent"], "default": "almond"}, {"key": "size", "label": "Size", "type": "enum", "tier": "basic", "options": ["small", "medium", "large", "very-large"], "default": "large"}, {"key": "iris_pattern", "label": "Iris Pattern", "type": "enum", "tier": "basic", "options": ["solid", "starburst", "ring", "speckled", "crystal", "flecked", "streaked"], "default": "starburst", "description": "Texture pattern visible in the iris at close range"}, {"key": "spacing", "label": "Spacing", "type": "enum", "tier": "intermediate", "options": ["close-set", "average", "wide-set"], "default": "average"}, {"key": "canthal_tilt", "label": "Canthal Tilt", "type": "enum", "tier": "intermediate", "options": ["positive", "neutral", "negative"], "default": "positive", "description": "Upward or downward slant of the outer eye corner relative to inner"}, {"key": "palpebral_fissure", "label": "Eye Opening", "type": "enum", "tier": "intermediate", "options": ["narrow", "average", "wide", "very-wide"], "default": "average", "description": "Height of the visible eye opening (palpebral fissure)"}, {"key": "epicanthic_fold", "label": "Epicanthic Fold", "type": "enum", "tier": "intermediate", "options": ["none", "subtle", "moderate", "prominent"], "default": "none", "description": "Skin fold covering the inner eye corner"}, {"key": "lash_length", "label": "Lash Length", "type": "enum", "tier": "intermediate", "options": ["short", "medium", "long", "very-long"], "default": "long"}, {"key": "lash_density", "label": "Lash Density", "type": "enum", "tier": "intermediate", "options": ["sparse", "average", "thick", "very-thick"], "default": "thick"}, {"key": "lash_curl", "label": "Lash Curl", "type": "enum", "tier": "intermediate", "options": ["straight", "natural", "curled", "dramatic"], "default": "natural"}, {"key": "eye_depth", "label": "Eye Depth", "type": "enum", "tier": "advanced", "options": ["protruding", "average", "deep-set", "very-deep-set"], "default": "average", "description": "How deeply the eye sits in the orbital socket"}, {"key": "limbal_ring", "label": "Limbal Ring", "type": "enum", "tier": "advanced", "options": ["none", "subtle", "defined", "dark"], "default": "defined", "description": "Dark ring at the outer edge of the iris \u2014 reads as youthfulness"}, {"key": "iris_to_sclera", "label": "Iris-to-Sclera Ratio", "type": "enum", "tier": "advanced", "options": ["small-iris", "average", "large-iris", "very-large-iris"], "default": "large-iris", "description": "How much of the visible eye the iris fills (large = doe-eyed)"}, {"key": "sclera_color", "label": "Sclera Color", "type": "enum", "tier": "advanced", "options": ["bright-white", "off-white", "ivory", "blue-tinted"], "default": "bright-white"}, {"key": "under_eye", "label": "Under-Eye Area", "type": "enum", "tier": "advanced", "options": ["smooth", "slight-shadow", "defined-shadow", "hollow", "puffy"], "default": "smooth"}, {"key": "brow_shape", "label": "Brow Shape", "type": "enum", "tier": "advanced", "options": ["straight", "arched", "rounded", "angular", "S-shaped"], "default": "arched", "description": "Overlaps with eyebrows module \u2014 kept here for eye-framing context"}, {"key": "expression_default", "label": "Default Expression", "type": "text", "tier": "advanced", "description": "Default eye expression at rest"}, {"key": "heterochromia", "label": "Heterochromia", "type": "boolean", "tier": "advanced", "default": false}, {"key": "secondary_color", "label": "Secondary Iris Color", "type": "color", "tier": "advanced"}, {"key": "interpupillary_distance", "label": "Interpupillary Distance", "type": "measurement", "tier": "clinical", "description": "Distance between pupil centers \u2014 governs face-width perception", "units": ["mm"], "defaultUnit": "mm", "min": 50, "max": 75, "step": 0.5, "default": {"value": 62, "unit": "mm"}}, {"key": "palpebral_width", "label": "Palpebral Width", "type": "measurement", "tier": "clinical", "description": "Horizontal eye opening width", "units": ["mm"], "defaultUnit": "mm", "min": 20, "max": 35, "step": 0.5, "default": {"value": 28, "unit": "mm"}}]'::jsonb WHERE slug = 'eyes';

-- mouth: 18 parameters
UPDATE luv_chassis_modules SET parameter_schema = '[{"key": "lip_shape", "label": "Lip Shape", "type": "enum", "tier": "basic", "options": ["thin", "medium", "full", "bow", "heart", "wide", "rosebud"], "default": "full"}, {"key": "lip_color", "label": "Lip Color", "type": "color", "tier": "basic", "default": "#CC6677"}, {"key": "lip_fullness", "label": "Lip Fullness", "type": "enum", "tier": "basic", "options": ["very-thin", "thin", "medium", "full", "very-full", "pillowy"], "default": "full", "description": "Overall volume of both lips together"}, {"key": "upper_to_lower_ratio", "label": "Upper/Lower Lip Ratio", "type": "ratio", "tier": "intermediate", "ratioLabels": ["Upper", "Lower"], "min": 0, "max": 1, "step": 0.05, "default": {"a": 0.4, "b": 0.6}}, {"key": "mouth_width", "label": "Mouth Width", "type": "enum", "tier": "intermediate", "options": ["narrow", "average", "wide", "very-wide"], "default": "average"}, {"key": "cupids_bow", "label": "Cupid''s Bow", "type": "enum", "tier": "intermediate", "options": ["flat", "subtle", "defined", "pronounced", "peaked"], "default": "defined", "description": "Shape definition of the upper lip''s central dip"}, {"key": "lip_texture", "label": "Lip Texture", "type": "enum", "tier": "intermediate", "options": ["smooth", "natural", "slightly-lined", "lined"], "default": "smooth"}, {"key": "vermilion_border", "label": "Vermilion Border", "type": "enum", "tier": "intermediate", "options": ["soft", "defined", "sharp", "overdrawn"], "default": "defined", "description": "Crispness of the lip-to-skin boundary line"}, {"key": "commissure_angle", "label": "Commissure Angle", "type": "enum", "tier": "advanced", "options": ["downturned", "neutral", "upturned"], "default": "neutral", "description": "Resting angle of mouth corners \u2014 affects perceived mood"}, {"key": "philtrum_shape", "label": "Philtrum Shape", "type": "enum", "tier": "advanced", "options": ["flat", "shallow", "defined", "deep"], "default": "defined", "description": "The vertical groove between nose and upper lip"}, {"key": "philtrum_length", "label": "Philtrum Length", "type": "enum", "tier": "advanced", "options": ["short", "average", "long"], "default": "average", "description": "Distance from nose base to lip \u2014 short reads younger"}, {"key": "lip_symmetry", "label": "Lip Symmetry", "type": "enum", "tier": "advanced", "options": ["symmetric", "slight-asymmetry", "noticeable-asymmetry"], "default": "symmetric"}, {"key": "expression_default", "label": "Default Expression", "type": "text", "tier": "advanced", "description": "Default mouth expression at rest"}, {"key": "dimples", "label": "Dimples", "type": "enum", "tier": "advanced", "options": ["none", "subtle", "defined", "deep"], "default": "none"}, {"key": "gum_show", "label": "Gum Show", "type": "enum", "tier": "advanced", "options": ["none", "slight", "moderate"], "default": "none", "description": "How much gum is visible during a full smile"}, {"key": "mouth_width_mm", "label": "Mouth Width", "type": "measurement", "tier": "clinical", "description": "Commissure to commissure distance", "units": ["mm"], "defaultUnit": "mm", "min": 35, "max": 65, "step": 0.5, "default": {"value": 50, "unit": "mm"}}, {"key": "upper_lip_height", "label": "Upper Lip Height", "type": "measurement", "tier": "clinical", "description": "Vermilion height at Cupid''s bow peak", "units": ["mm"], "defaultUnit": "mm", "min": 5, "max": 15, "step": 0.5, "default": {"value": 8, "unit": "mm"}}, {"key": "lower_lip_height", "label": "Lower Lip Height", "type": "measurement", "tier": "clinical", "description": "Vermilion height at center", "units": ["mm"], "defaultUnit": "mm", "min": 7, "max": 18, "step": 0.5, "default": {"value": 10, "unit": "mm"}}]'::jsonb WHERE slug = 'mouth';

-- nose: 17 parameters
UPDATE luv_chassis_modules SET parameter_schema = '[{"key": "profile", "label": "Profile Shape", "type": "enum", "tier": "basic", "options": ["button", "snub", "straight", "aquiline", "Greek", "nubian", "celestial", "Roman"], "default": "button", "description": "Nose shape as seen from the side"}, {"key": "size", "label": "Overall Size", "type": "enum", "tier": "basic", "options": ["small", "medium", "large", "prominent"], "default": "small"}, {"key": "bridge_width", "label": "Bridge Width", "type": "enum", "tier": "intermediate", "options": ["narrow", "average", "wide"], "default": "narrow"}, {"key": "bridge_height", "label": "Bridge Height", "type": "enum", "tier": "intermediate", "options": ["flat", "low", "medium", "high", "very-high"], "default": "medium", "description": "How far the nasal bridge projects from the face plane"}, {"key": "tip", "label": "Tip Shape", "type": "enum", "tier": "intermediate", "options": ["upturned", "rounded", "pointed", "bulbous", "bifid"], "default": "rounded"}, {"key": "tip_projection", "label": "Tip Projection", "type": "enum", "tier": "intermediate", "options": ["under-projected", "average", "projected", "over-projected"], "default": "average", "description": "How far the nasal tip extends forward from the face"}, {"key": "nostril_shape", "label": "Nostril Shape", "type": "enum", "tier": "intermediate", "options": ["narrow", "oval", "round", "flared", "teardrop"], "default": "oval"}, {"key": "dorsum", "label": "Dorsum Line", "type": "enum", "tier": "advanced", "options": ["concave", "straight", "slightly-convex", "convex", "humped"], "default": "straight", "description": "The profile line of the nasal bridge \u2014 concave = ski-slope, convex = Roman"}, {"key": "alar_width", "label": "Alar Width", "type": "enum", "tier": "advanced", "options": ["narrow", "proportionate", "wide", "flared"], "default": "proportionate", "description": "Width of the nostril wings (alae) relative to intercanthal distance"}, {"key": "nasofrontal_angle", "label": "Nasofrontal Angle", "type": "enum", "tier": "advanced", "options": ["shallow", "average", "deep"], "default": "average", "description": "Depth of the angle where nose meets the brow \u2014 deeper = more defined bridge"}, {"key": "nasolabial_angle", "label": "Nasolabial Angle", "type": "enum", "tier": "advanced", "options": ["acute", "right-angle", "obtuse"], "default": "obtuse", "description": "Angle between nose underside and upper lip \u2014 obtuse = upturned appearance"}, {"key": "tip_rotation", "label": "Tip Rotation", "type": "enum", "tier": "advanced", "options": ["drooping", "neutral", "slightly-upturned", "upturned", "over-rotated"], "default": "slightly-upturned", "description": "Vertical angle of the nasal tip"}, {"key": "septum_show", "label": "Columellar Show", "type": "enum", "tier": "advanced", "options": ["hidden", "minimal", "moderate", "visible"], "default": "minimal", "description": "How much of the nasal septum/columella is visible from a frontal view"}, {"key": "skin_thickness", "label": "Nasal Skin Thickness", "type": "enum", "tier": "advanced", "options": ["thin", "medium", "thick"], "default": "medium", "description": "Thin skin reveals cartilage definition; thick skin smooths contours"}, {"key": "nose_length", "label": "Nose Length", "type": "measurement", "tier": "clinical", "description": "Radix (bridge root) to tip", "units": ["mm"], "defaultUnit": "mm", "min": 35, "max": 60, "step": 0.5, "default": {"value": 48, "unit": "mm"}}, {"key": "nose_width", "label": "Nose Width", "type": "measurement", "tier": "clinical", "description": "Alar base width \u2014 ideally \u2248 intercanthal distance", "units": ["mm"], "defaultUnit": "mm", "min": 25, "max": 50, "step": 0.5, "default": {"value": 34, "unit": "mm"}}, {"key": "tip_projection_mm", "label": "Tip Projection", "type": "measurement", "tier": "clinical", "description": "Alar crease to tip \u2014 Goode ratio (projection/length) ideally 0.55\u20130.60", "units": ["mm"], "defaultUnit": "mm", "min": 15, "max": 35, "step": 0.5, "default": {"value": 27, "unit": "mm"}}]'::jsonb WHERE slug = 'nose';

-- skeletal: 21 parameters
UPDATE luv_chassis_modules SET parameter_schema = '[{"key": "frame", "label": "Frame", "type": "enum", "tier": "basic", "options": ["delicate", "small", "medium", "large", "robust"], "default": "medium"}, {"key": "face_shape", "label": "Face Shape", "type": "enum", "tier": "basic", "options": ["oval", "round", "square", "heart", "diamond", "oblong", "inverted-triangle", "pear"], "default": "oval"}, {"key": "face_length", "label": "Face Length", "type": "enum", "tier": "basic", "options": ["short", "average", "long", "very-long"], "default": "average", "description": "Vertical proportion independent of face shape"}, {"key": "cheekbones", "label": "Cheekbone Prominence", "type": "enum", "tier": "intermediate", "options": ["flat", "subtle", "defined", "prominent", "high", "very-high"], "default": "defined"}, {"key": "jawline", "label": "Jawline", "type": "enum", "tier": "intermediate", "options": ["soft", "rounded", "defined", "angular", "sharp", "chiseled"], "default": "soft"}, {"key": "jaw_width", "label": "Jaw Width", "type": "enum", "tier": "intermediate", "options": ["narrow", "tapered", "average", "wide", "square"], "default": "tapered", "description": "Width at the mandibular angle relative to cheekbones"}, {"key": "chin", "label": "Chin Shape", "type": "enum", "tier": "intermediate", "options": ["receding", "small", "average", "prominent", "pointed", "cleft", "round"], "default": "small"}, {"key": "forehead", "label": "Forehead Height", "type": "enum", "tier": "intermediate", "options": ["low", "average", "high", "very-high"], "default": "average"}, {"key": "forehead_slope", "label": "Forehead Slope", "type": "enum", "tier": "intermediate", "options": ["vertical", "slight-slope", "moderate", "receding"], "default": "slight-slope", "description": "Profile angle of the forehead"}, {"key": "temple_width", "label": "Temple Width", "type": "enum", "tier": "intermediate", "options": ["narrow", "average", "wide"], "default": "average"}, {"key": "orbital_depth", "label": "Orbital Depth", "type": "enum", "tier": "advanced", "options": ["protruding", "shallow", "average", "deep", "very-deep"], "default": "average", "description": "How deeply the eye sockets are set \u2014 affects shadow and eye prominence"}, {"key": "zygomatic_width", "label": "Zygomatic Width", "type": "enum", "tier": "advanced", "options": ["narrow", "average", "wide", "very-wide"], "default": "average", "description": "Widest point across the cheekbones \u2014 the face''s widest landmark"}, {"key": "mandibular_angle", "label": "Mandibular Angle", "type": "enum", "tier": "advanced", "options": ["rounded", "obtuse", "average", "defined", "sharp"], "default": "average", "description": "Angle at the jaw corner \u2014 sharper reads more structured"}, {"key": "chin_projection", "label": "Chin Projection", "type": "enum", "tier": "advanced", "options": ["receding", "average", "projected", "prominent"], "default": "average", "description": "How far the chin extends forward in profile"}, {"key": "brow_ridge", "label": "Brow Ridge", "type": "enum", "tier": "advanced", "options": ["flat", "subtle", "moderate", "prominent"], "default": "subtle", "description": "Supraorbital ridge prominence \u2014 affects brow shadow and perceived intensity"}, {"key": "facial_symmetry", "label": "Facial Symmetry", "type": "enum", "tier": "advanced", "options": ["highly-symmetric", "slight-asymmetry", "noticeable-asymmetry"], "default": "highly-symmetric"}, {"key": "facial_thirds", "label": "Facial Thirds Balance", "type": "enum", "tier": "advanced", "options": ["upper-dominant", "balanced", "mid-dominant", "lower-dominant"], "default": "balanced", "description": "Which facial third (hairline-brow, brow-nose, nose-chin) is proportionally largest"}, {"key": "bizygomatic_width", "label": "Bizygomatic Width", "type": "measurement", "tier": "clinical", "description": "Widest point across cheekbones", "units": ["mm"], "defaultUnit": "mm", "min": 110, "max": 155, "step": 0.5, "default": {"value": 130, "unit": "mm"}}, {"key": "bigonial_width", "label": "Bigonial Width", "type": "measurement", "tier": "clinical", "description": "Width across mandibular angles (jaw corners)", "units": ["mm"], "defaultUnit": "mm", "min": 80, "max": 130, "step": 0.5, "default": {"value": 100, "unit": "mm"}}, {"key": "face_height", "label": "Total Face Height", "type": "measurement", "tier": "clinical", "description": "Trichion (hairline) to menton (chin bottom)", "units": ["mm"], "defaultUnit": "mm", "min": 150, "max": 210, "step": 0.5, "default": {"value": 180, "unit": "mm"}}, {"key": "facial_index", "label": "Facial Index", "type": "range", "tier": "clinical", "description": "Face height / bizygomatic width \u2014 <0.87 euryprosopic (wide), >0.97 leptoprosopic (long)", "min": 0.7, "max": 1.1, "step": 0.01, "default": 0.88}]'::jsonb WHERE slug = 'skeletal';
